import { Component, Input, Output, EventEmitter, HostListener, OnChanges, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-modal',
  template: `
    <div
      *ngIf="open"
      (click)="close()"
      style="position: fixed; inset: 0; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 1000;"
    >
      <div
        role="dialog"
        aria-modal="true"
        [attr.aria-label]="title"
        (click)="$event.stopPropagation()"
        style="background: #fff; border-radius: 10px; padding: 24px; width: min(420px, 90vw); box-shadow: 0 10px 40px rgba(0,0,0,0.2);"
      >
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px;">
          <h2 style="margin: 0; font-size: 18px;">{{ title }}</h2>
          <button (click)="close()" aria-label="Close" style="border: none; background: none; font-size: 20px; cursor: pointer;">✕</button>
        </div>
        <ng-content></ng-content>
      </div>
    </div>
  `,
})
export class ModalComponent implements OnChanges, OnDestroy {
  @Input() open = false;
  @Input() title = '';
  @Output() closed = new EventEmitter<void>();

  close(): void {
    this.closed.emit();
  }

  @HostListener('document:keydown.escape')
  onEsc(): void {
    if (this.open) {
      this.close();
    }
  }

  ngOnChanges(): void {
    document.body.style.overflow = this.open ? 'hidden' : '';
  }

  ngOnDestroy(): void {
    document.body.style.overflow = '';
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Modal Demo</h1>
      <button (click)="open = true" style="padding: 8px 16px; cursor: pointer;">Open modal</button>
      <app-modal [open]="open" (closed)="open = false" title="Confirm action">
        <p>Are you sure you want to continue? This is a controlled modal.</p>
        <div style="display: flex; gap: 8px; justify-content: flex-end;">
          <button (click)="open = false" style="padding: 6px 14px; cursor: pointer;">Cancel</button>
          <button (click)="open = false" style="padding: 6px 14px; cursor: pointer; background: #2563eb; color: #fff; border: none; border-radius: 4px;">Confirm</button>
        </div>
      </app-modal>
    </div>
  `,
})
export class AppComponent {
  open = false;
}

@NgModule({
  declarations: [AppComponent, ModalComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
